{"content":"     1	import Foundation
     2	import Observation
     3	
     4	/// The root observable. Single source of truth for the active library,
     5	/// current wall, style, axis, and indexing progress.
     6	///
     7	/// Kept deliberately small — most interaction goes through dedicated child
     8	/// view-models (WallModel, IndexModel) that this observable wires together.
     9	@Observable
    10	public final class AppModel {
    11	
    12	    public enum Phase: Equatable {
    13	        /// No library chosen yet. Renders the landing hero.
    14	        case landing
    15	        /// Indexing the chosen library. Carries the raw snapshot (stage +
    16	        /// counts) so the view layer formats the progress message with
    17	        /// LocalizedStringKey at render time — a pre-formatted String
    18	        /// would bake in the call-time locale and break in-session
    19	        /// language switching.
    20	        case indexing(IndexingSnapshot)
    21	        /// Library ready; a wall has been composed (or is empty awaiting Shuffle).
    22	        case ready
    23	    }
    24	
    25	    public var phase: Phase = .landing
    26	    public var style: Style = .exhibit
    27	    public var axis: ClusterAxis = .color
    28	    public var wall: Wall = .empty
    29	
    30	    /// URL of the folder the user picked, if any. Persisted via a
    31	    /// security-scoped bookmark inside ``LibraryBookmark``.
    32	    public var libraryURL: URL?
    33	
    34	    /// Full set of photos in the active library's index, newest first.
    35	    /// Populated by the Indexer once it reaches the `done` stage.
    36	    public var photos: [Photo] = []
    37	
    38	    /// Photos the user has pinned. These are guaranteed to appear in every
    39	    /// Shuffle until unpinned — position may change, inclusion doesn't.
    40	    public var lockedPhotoIDs: Set<PhotoID> = []
    41	
    42	    /// Active permission prompt (nil = none showing). Set by the
    43	    /// coordinator based on system auth status; RootScene renders the
    44	    /// corresponding sheet.
    45	    public var permissionPrompt: PermissionPrompt?
    46	
    47	    /// A rolling buffer of the most recently indexed photos, used by the
    48	    /// indexing view to grow a live mini-wall in real time. Capped so the
    49	    /// array doesn't balloon during scans of 50k+ libraries.
    50	    public var recentlyIndexed: [Photo] = []
    51	    private let recentlyIndexedCap = 96
    52	
    53	    /// User-facing language override. Persisted; applied at runtime via
    54	    /// `.environment(\.locale, …)` on the root scene.
    55	    public var languagePreference: LanguagePreference = LanguagePreference.persisted
    56	
    57	    /// Hand-sense (camera-driven gestures) enablement. Persisted —
    58	    /// if the user turned it on previously and granted camera access,
    59	    /// Loom auto-starts capture next launch.
    60	    public var handSenseEnabled: Bool = HandSensePreference.enabled
    61	
    62	    /// Continuous openness scalar driven by ``HandSense``. 0 = fist
    63	    /// (tiles pull together), 0.5 = neutral (composition as laid),
    64	    /// 1 = open palm (tiles spread). Consumed by WallCanvas as a
    65	    /// spread factor around the canvas center.
    66	    public var wallOpenness: Double = 0.5
    67	
    68	    /// How tightly photos pack on the wall. Read by the Composer at
    69	    /// every Shuffle to scale the target tile count. Persisted.
    70	    public var density: WallDensity = WallDensity.persisted
    71	
    72	    /// Skip blurry, overexposed, and tiny photos during composition.
    73	    /// Default on — most users want a curated wall. Power users can
    74	    /// disable in Settings to see every photo in the library.
    75	    public var filterQuality: Bool = QualityFilterPreference.enabled
    76	
    77	    /// Trim near-black or near-white borders from photos on the wall
    78	    /// and in the grid browser. Detected at index time; default on.
    79	    public var autoTrimEnabled: Bool = AutoTrimPreference.enabled
    80	
    81	    public init() {}
    82	
    83	    public func setStyle(_ s: Style) { style = s }
    84	    public func setAxis(_ a: ClusterAxis) { axis = a }
    85	
    86	    public func setPhotos(_ p: [Photo]) { photos = p }
    87	
    88	    public func setPhase(_ p: Phase) { phase = p }
    89	
    90	    public func toggleLock(_ id: PhotoID) {
    91	        if lockedPhotoIDs.contains(id) {
    92	            lockedPhotoIDs.remove(id)
    93	        } else {
    94	            lockedPhotoIDs.insert(id)
    95	        }
    96	    }
    97	
    98	    public func clearLocks() { lockedPhotoIDs.removeAll() }
    99	
   100	    public func present(_ prompt: PermissionPrompt) { permissionPrompt = prompt }
   101	    public func dismissPermissionPrompt()            { permissionPrompt = nil }
   102	
   103	    public func pushIndexed(_ photo: Photo) {
   104	        recentlyIndexed.append(photo)
   105	        if recentlyIndexed.count > recentlyIndexedCap {
   106	            recentlyIndexed.removeFirst(recentlyIndexed.count - recentlyIndexedCap)
   107	        }
   108	    }
   109	
   110	    public func clearIndexed() { recentlyIndexed.removeAll() }
   111	
   112	    public func setLanguage(_ pref: LanguagePreference) {
   113	        languagePreference = pref
   114	        LanguagePreference.persisted = pref
   115	    }
   116	
   117	    public func setHandSenseEnabled(_ enabled: Bool) {
   118	        handSenseEnabled = enabled
   119	        HandSensePreference.enabled = enabled
   120	        if !enabled {
   121	            // Reset openness so disabling doesn't leave the wall frozen
   122	            // in whatever spread state the last gesture produced.
   123	            wallOpenness = 0.5
   124	        }
   125	    }
   126	
   127	    public func setOpenness(_ value: Double) {
   128	        wallOpenness = max(0, min(1, value))
   129	    }
   130	
   131	    public func setDensity(_ d: WallDensity) {
   132	        density = d
   133	        WallDensity.persisted = d
   134	    }
   135	
   136	    public func setFilterQuality(_ enabled: Bool) {
   137	        filterQuality = enabled
   138	        QualityFilterPreference.enabled = enabled
   139	    }
   140	
   141	    public func setAutoTrimEnabled(_ enabled: Bool) {
   142	        autoTrimEnabled = enabled
   143	        AutoTrimPreference.enabled = enabled
   144	    }
   145	}
   146	
   147	public enum QualityFilterPreference {
   148	    private static let key = "loom.filterQuality"
   149	
   150	    public static var enabled: Bool {
   151	        get {
   152	            // Default to true on first launch (key absent → true).
   153	            if UserDefaults.standard.object(forKey: key) == nil { return true }
   154	            return UserDefaults.standard.bool(forKey: key)
   155	        }
   156	        set { UserDefaults.standard.set(newValue, forKey: key) }
   157	    }
   158	}
   159	
   160	/// Persistence for the auto-trim border switch.
   161	public enum AutoTrimPreference {
   162	    private static let key = "loom.autoTrimEnabled"
   163	
   164	    public static var enabled: Bool {
   165	        get {
   166	            // Default to true on first launch (key absent → true).
   167	            if UserDefaults.standard.object(forKey: key) == nil { return true }
   168	            return UserDefaults.standard.bool(forKey: key)
   169	        }
   170	        set { UserDefaults.standard.set(newValue, forKey: key) }
   171	    }
   172	}
   173	
   174	/// Persistence for the hand-sense master switch. Kept separate from
   175	/// ``AppModel`` so launch-time coordinators can read it before an
   176	/// AppModel instance exists.
   177	public enum HandSensePreference {
   178	    private static let key = "loom.handSenseEnabled"
   179	
   180	    public static var enabled: Bool {
   181	        get { UserDefaults.standard.bool(forKey: key) }
   182	        set { UserDefaults.standard.set(newValue, forKey: key) }
   183	    }
   184	}
