     2	import LoomCore
     3	import LoomDesign
     4	
     5	/// A compact menu that lets the user flip the clustering axis.
     6	///
     7	/// Sits as a small pill inside the wall chrome. Click opens a Menu listing
     8	/// the axes; each shows whether it's available yet (color is v1; mood/scene/
     9	/// people/time come later). Unavailable axes render disabled with a
    10	/// "coming soon" note so users see the roadmap without friction.
    11	public struct AxisToggle: View {
    12	
    13	    @Binding public var selected: ClusterAxis
    14	    public let onChange: (ClusterAxis) -> Void
    15	
    16	    public init(
    17	        selected: Binding<ClusterAxis>,
    18	        onChange: @escaping (ClusterAxis) -> Void
    19	    ) {
    20	        self._selected = selected
    21	        self.onChange = onChange
    22	    }
    23	
    24	    public var body: some View {
    25	        Menu {
    26	            ForEach(ClusterAxis.allCases, id: \.self) { axis in
    27	                Button {
    28	                    selected = axis
    29	                    onChange(axis)
    30	                } label: {
    31	                    HStack {
    32	                        Text(axis.displayName)
    33	                        Spacer()
    34	                        if !isAvailable(axis) {
    35	                            Text("soon")
    36	                                .font(.caption2)
    37	                                .foregroundStyle(.secondary)
    38	                        }
    39	                    }
    40	                }
    41	                .disabled(!isAvailable(axis))
    42	            }
    43	        } label: {
    44	            HStack(spacing: LoomSpacing.xs) {
    45	                Image(systemName: "circle.grid.cross")
    46	                    .font(.system(size: 11, weight: .semibold))
    47	                Text(selected.displayName)
    48	                    .font(LoomType.caption)
    49	            }
    50	            .foregroundStyle(Palette.inkMuted)
    51	            .padding(.horizontal, LoomSpacing.md)
    52	            .padding(.vertical, LoomSpacing.xs + 2)
    53	            .background(Capsule().fill(Palette.surface.opacity(0.7)))
    54	            .overlay(Capsule().strokeBorder(Palette.hairline, lineWidth: 1))
    55	        }
    56	        .menuStyle(.borderlessButton)
    57	        .menuIndicator(.hidden)
    58	        .fixedSize()
    59	    }
    60	
    61	    private func isAvailable(_ axis: ClusterAxis) -> Bool {
    62	        axis == .color || axis == .mood
    63	    }
    64	}
