{"content":"     1	import SwiftUI
     2	import LoomCore
     3	import LoomDesign
     4	
     5	/// The floating toolbar at the bottom of the wall.
     6	///
     7	/// **Auto-hide**: appears on launch, fades out after ~3s of idle, slides
     8	/// back in when the cursor approaches the bottom edge. During hover the
     9	/// chrome stays solid; on exit the idle timer restarts.
    10	///
    11	/// **Layout**: two groups separated by breathing room (no explicit divider).
    12	/// Secondary controls (Axis / Style) sit left as quiet text chips;
    13	/// the primary Shuffle button sits right in brass. Material-backed with
    14	/// a warm canvas tint — frosted glass that belongs on the paper canvas
    15	/// rather than fighting it.
    16	public struct WallChrome: View {
    17	
    18	    @Environment(AppModel.self) private var app
    19	    public let shuffle: () -> Void
    20	    public let isNarrow: Bool
    21	
    22	    @State private var hoveredChip: Chip?
    23	
    24	    private enum Chip: Hashable { case axis, style }
    25	
    26	    public init(shuffle: @escaping () -> Void, isNarrow: Bool = false) {
    27	        self.shuffle = shuffle
    28	        self.isNarrow = isNarrow
    29	    }
    30	
    31	    public var body: some View {
    32	        HStack(spacing: 0) {
    33	            axisChip
    34	            separator
    35	            styleChip
    36	
    37	            Spacer()
    38	                .frame(width: LoomSpacing.lg)
    39	
    40	            ShuffleButton(showShortcut: !isNarrow, action: shuffle)
    41	        }
    42	        .padding(.horizontal, LoomSpacing.md)
    43	        .padding(.vertical, LoomSpacing.xs + 2)
    44	        .background(
    45	            Capsule(style: .continuous)
    46	                .fill(.ultraThinMaterial)
    47	        )
    48	        .background(
    49	            Capsule(style: .continuous)
    50	                .fill(Palette.canvas.opacity(0.55))
    51	        )
    52	        .overlay(
    53	            Capsule(style: .continuous)
    54	                .strokeBorder(Palette.hairline.opacity(0.6), lineWidth: 0.5)
    55	        )
    56	        .shadow(
    57	            color: LoomShadow.tone.opacity(0.10),
    58	            radius: 20, x: 0, y: 8
    59	        )
    60	        .shadow(
    61	            color: LoomShadow.tone.opacity(0.04),
    62	            radius: 2, x: 0, y: 1
    63	        )
    64	    }
    65	
    66	    // MARK: — Chips
    67	
    68	    private var axisChip: some View {
    69	        Menu {
    70	            ForEach(ClusterAxis.allCases, id: \.self) { axis in
    71	                Button {
    72	                    app.setAxis(axis)
    73	                    shuffle()
    74	                } label: {
    75	                    HStack {
    76	                        Text(axis.displayName)
    77	                        Spacer()
    78	                        if axis == app.axis {
    79	                            Image(systemName: "checkmark")
    80	                        } else if !isAvailable(axis) {
    81	                            Text("soon")
    82	                                .font(.caption2)
    83	                                .foregroundStyle(.secondary)
    84	                        }
    85	                    }
    86	                }
    87	                .disabled(!isAvailable(axis))
    88	            }
    89	        } label: {
    90	            chipLabel(Text(app.axis.displayName), kind: .axis)
    91	        }
    92	        .menuStyle(.borderlessButton)
    93	        .menuIndicator(.hidden)
    94	        .fixedSize()
    95	    }
    96	
    97	    private var styleChip: some View {
    98	        Menu {
    99	            ForEach(Style.allCases) { style in
   100	                Button {
   101	                    app.setStyle(style)
   102	                    shuffle()
   103	                } label: {
   104	                    HStack {
   105	                        Text(style.displayName)
   106	                        Spacer()
   107	                        if style == app.style {
   108	                            Image(systemName: "checkmark")
   109	                        }
   110	                    }
   111	                }
   112	            }
   113	        } label: {
   114	            chipLabel(Text(app.style.displayName), kind: .style)
   115	        }
   116	        .menuStyle(.borderlessButton)
   117	        .menuIndicator(.hidden)
   118	        .fixedSize()
   119	    }
   120	
   121	    private func chipLabel(_ text: Text, kind: Chip) -> some View {
   122	        HStack(spacing: LoomSpacing.xs) {
   123	            text
   124	                .font(LoomType.caption)
   125	                .lineLimit(1)
   126	                .fixedSize(horizontal: true, vertical: false)
   127	                .foregroundStyle(Palette.ink)
   128	            Image(systemName: "chevron.down")
   129	                .font(.system(size: 7, weight: .semibold))
   130	                .foregroundStyle(Palette.inkFaint)
   131	        }
   132	        .padding(.horizontal, LoomSpacing.sm + 2)
   133	        .padding(.vertical, LoomSpacing.xs + 2)
   134	        .background(
   135	            Capsule(style: .continuous)
   136	                .fill(hoveredChip == kind
   137	                      ? Palette.ink.opacity(0.06)
   138	                      : Color.clear)
   139	        )
   140	        .onHover { entered in
   141	            if entered { hoveredChip = kind }
   142	            else if hoveredChip == kind { hoveredChip = nil }
   143	        }
   144	        .animation(LoomMotion.hover, value: hoveredChip)
   145	    }
   146	
   147	    // MARK: — Separator
   148	
   149	    private var separator: some View {
   150	        Text("·")
   151	            .font(.system(size: 11, weight: .light))
   152	            .foregroundStyle(Palette.inkFaint)
   153	            .padding(.horizontal, LoomSpacing.xs)
   154	    }
   155	
   156	    private func isAvailable(_ axis: ClusterAxis) -> Bool {
   157	        axis == .color || axis == .mood
   158	    }
   159	}
